  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1772190652933 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci COMMENT = '美食论坛' ROW_FORMAT = DYNAMIC;

